import "../quiz_question.dart";

const _subject = "Literature in English";

QuizQuestion _q(String text, List<String> options, String correct, String explanation) {
  return QuizQuestion(
    subject: _subject,
    text: text,
    options: options,
    correctIndex: options.indexOf(correct),
    explanation: explanation,
  );
}

/// WAEC Literature-in-English question bank covering literary appreciation
/// and terminology: elements of drama, elements of prose, elements of
/// poetry and figures of speech, and general analytical concepts. Since
/// WAEC's prescribed African/Non-African drama, prose, and poetry texts
/// rotate on a syllabus cycle, this bank focuses on the text-independent
/// terminology and analytical skills tested in Paper 1 (Objective) and
/// applicable to whichever texts a student is studying.
List<QuizQuestion> buildWaecLiteratureQuestions() {
  return [
    ..._elementsOfDrama,
    ..._elementsOfProse,
    ..._elementsOfPoetryAndFiguresOfSpeech,
    ..._generalAnalyticalConcepts,
  ];
}

